    body=f"""<section class='hero-card'><div class='eyebrow'>Proof Card {c['id']} · {esc(c['tag'])}</div><h1>{esc(c['title'])}</h1><p class='lead'>{esc(c['mission'])}</p><span class='pill'>{esc(c['level'])}</span></section><section class='section grid'><div class='panel'><h3>Problem</h3><p>{esc(c['problem'])}</p></div><div class='panel'><h3>Where AGIALPHA becomes useful</h3><p>{esc(c['agialpha'])}</p></div><div class='panel'><h3>RSI upgrade logic</h3><p>{esc(c['rsi'])}</p></div><div class='panel'><h3>Value</h3><p>{esc(c['value'])}</p></div></section><section class='section'><div class='panel'><div class='eyebrow'>Smart-contract / registry route</div><h2>How the proof work is coordinated</h2><div class='route'>{route_html}</div></div></section><section class='section'><div class='panel'><div class='eyebrow'>Large multi-agent coordination</div><h2>Sovereign enterprise operating theater</h2><p>The system coordinates specialized roles to maximum effect by requiring each role to emit an auditable artifact.</p><table class='table'><tr><th>Role</th><th>Function</th><th>Artifact</th></tr>{roles}</table></div></section><section class='section grid'><div class='panel'><h3>Goals used</h3><table class='table'><tr><th>Goal</th><th>Explanation</th></tr>{goals}</table></div><div class='panel'><h3>Plans used</h3><table class='table'><tr><th>Plan</th><th>Explanation</th></tr>{plans}</table></div><div class='panel'><h3>Skills used</h3><table class='table'><tr><th>Skill</th><th>Explanation</th></tr>{skills}</table></div></section><section class='section'><div class='panel'><div class='eyebrow'>Efficient RSI loop</div><h2>Proof-backed upgrade rights</h2><div class='flow'><div>Observe weakness</div><div>Improve artifact</div><div>Prove change</div><div>Review evidence</div><div>Select</div><div>Grant scoped upgrade rights</div><div>Reinvest verified value</div><div>Improve future work</div></div></div></section>{special}<section class='section'><div class='warning'><strong>Claim boundary:</strong> {esc(c['claim'])}</div></section>"""
    return wrap('Proof Card '+c['id'],body)
