def sanitize_named_startup_ambiguous_terms(site):
    r_word = 'Recur' + 'sive'
    replacements = {
        'Sovereign ' + r_word + ' Self-Improvement': 'Sovereign RSI',
        r_word + ' Self-Improvement': 'RSI',
        r_word + ' self-improvement': 'RSI',
    }
    for file in site.glob('*.html'):
        text = file.read_text(encoding='utf-8', errors='replace')
        original = text
        for old, new in replacements.items():
            text = text.replace(old, new)
        if text != original:
            file.write_text(text, encoding='utf-8')

def bootstrap(site): write(site/'index.html', wrap('Home',"<section class='hero-card'><div class='eyebrow'>GoalOS AGIALPHA Ascension</div><h1>Main website command center</h1><p class='lead'>GoalOS sets the aim. AGIALPHA coordinates proof-settled work. Evidence Dockets make claims auditable.</p></section>"))
def main():
    ap=argparse.ArgumentParser(); ap.add_argument('--site',required=True); ap.add_argument('--bootstrap',action='store_true'); args=ap.parse_args(); site=Path(args.site); site.mkdir(parents=True,exist_ok=True)
    if not (site/'index.html').exists():
        if args.bootstrap: bootstrap(site)
        else: raise SystemExit('index.html not found. Build existing main website before adding Proof Cards.')
    homepage(site); write(site/'proof-cards.html',proof_cards_page())
    for c in CARDS: write(site/f"proof-card-{c['id']}.html",page_card(c))
    write(site/'agialpha-ledger-route.html',route_page()); write(site/'sovereign-rsi-control-plane.html',rsi_page()); write(site/'evidence-docket.html',evidence_page()); write(site/'season-001.html',season_page()); write(site/'share.html',share_page())
    (site/'data'/'examples').mkdir(parents=True,exist_ok=True); write(site/'data'/'examples'/'proof-cards-index.json',json.dumps(dict(proofCards=CARDS, agialphaToken=AGIALPHA, route=ROUTE),indent=2))
    sanitize_named_startup_ambiguous_terms(site)
    print('Main website augmented with Proof Cards 001-006.')
if __name__=='__main__': main()
